def group_values(tree):
    if not tree:
        return []

    result = []
    current_level = []
    queue = [(tree, 0)]

    while queue:
        node, level = queue.pop(0)

        if level == len(result):
            if current_level:
                result.append(current_level)
            current_level = []

        current_level.append(node)

        if node.left:
            queue.append((node.left, level + 1))
        if node.right:
            queue.append((node.right, level + 1))

    if current_level:
        result.append(current_level)

    return result

